#include <algorithm>

using namespace std;

long long solve(vector<long long> weight) {
    int n = weight.size();
    if (n < 2) return 0;

    vector<int> next_smaller(n, n);
    stack<int> s;

    // Find the next smaller element for each position
    for (int i = 0; i < n; ++i) {
        while (!s.empty() && weight[i] < weight[s.top()]) {
            next_smaller[s.top()] = i;
            s.pop();
        }
        s.push(i);
    }

    int res = 0;
    int i = 0;
    while (i < n) {
        int j = i + 1;
        int max_pos = i;
        while (j < n && weight[j] >= weight[i]) {
            if (weight[j] > weight[max_pos]) {
                max_pos = j;
            }
            j++;
        }
        if (j - i >= 2 && weight[j - 1] < weight[max_pos]) {
            res++;
            i = j;
        } else {
            // Check if there's a valid segment starting at i
            bool found = false;
            for (int k = i + 1; k < next_smaller[i]; ++k) {
                if (weight[k] > weight[i] && (k + 1 == next_smaller[i] || weight[k + 1] < weight[k])) {
                    res++;
                    i = k + 1;
                    found = true;
                    break;
                }
            }
            if (!found) {
                i++;
            }
        }
    }

    return res;
}
